package main

import (
	"github.com/gin-gonic/gin"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/stdlib"
	"net/http"
)

type User struct {
	ID       int64
	Name     string
	Age      int
	Email    string
}

func main() {
	// Initialize PostgreSQL connection
	conn, err := pgx.ConnectStdEnv("postgres://user:password@localhost:5432/mydb")
	if err != nil {
		panic(err)
	}
	defer conn.Close()

	// Initialize Gin router
	r := gin.Default()

	// Define routes
	r.POST("/users", createUser)
	r.GET("/users/:id", getUser)
	r.PUT("/users/:id", updateUser)
	r.DELETE("/users/:id", deleteUser)

	// Start server
	r.Run(":8080")
}

// createUser creates a new user
func createUser(c *gin.Context) {
	var user User
	c.BindJSON(&user)

	// Insert into database
	_, err := conn.Exec("INSERT INTO users (name, age, email) VALUES ($1, $2, $3)", user.Name, user.Age, user.Email)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create user"})
		return
	}

	c.JSON(http.StatusCreated, user)
}

// getUser retrieves a user by ID
func getUser(c *gin.Context) {
	id := c.Param("id")
	var user User

	// Query database
	err := conn.QueryRow("SELECT id, name, age, email FROM users WHERE id = $1", id).Scan(&user.ID, &user.Name, &user.Age, &user.Email)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
		return
	}

	c.JSON(http.StatusOK, user)
}

// updateUser updates a user by ID
func updateUser(c *gin.Context) {
	id := c.Param("id")
	var user User
	c.BindJSON(&user)

	// Update database
	_, err := conn.Exec("UPDATE users SET name = $1, age = $2, email = $3 WHERE id = $4", user.Name, user.Age, user.Email, id)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update user"})
		return
	}

	c.JSON(http.StatusOK, user)
}

// deleteUser deletes a user by ID
func deleteUser(c *gin.Context) {
	id := c.Param("id")

	// Delete from database
	_, err := conn.Exec("DELETE FROM users WHERE id = $1", id)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to delete user"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "User deleted"})
}

package main

import (
	"fmt"
	"os"
	"path/filepath"
