type Photo struct {
	ID       string
	Date     string
	Category string
	Description string
}

type Archive struct {
	photos []*Photo
}

func (a *Archive) AddPhoto(date, category, description string) {
	id := fmt.Sprintf("%d", len(a.photos)+1)
	a.photos = append(a.photos, &Photo{
		ID:       id,
		Date:     date,
		Category: category,
		Description: description,
	})
}

func (a *Archive) Report() map[string][]string {
	report := make(map[string][]string)
	for _, photo := range a.photos {
		report[photo.Category] = append(report[photo.Category], photo.Description)
	}
	return report
}

func main() {
	// Initialize Cobra
	cmd := Cobra{
		Name:         "photoarchive",
		Version:      "1.0",
		Copyright:    "2025",
		Short:        "Manage personal digital photography archive",
		Long:         "CLI application for managing personal digital photography archive",
		Commands:     []*cobra.Command{},
		RootCmd:      &cobra.Command{},
		Out:          os.Stdout,
		ErrOut:       os.Stderr,
	}

	// Initialize command
	cmd.Commands = append(cmd.Commands, &cobra.Command{
		Name:   "init",
		Short: "Initialize a new archive",
		Args:  0,
		RunE: func(cmd *cobra.Command, args []string) error {
			// Create directory structure
			dir := filepath.Join(os.Getenv("HOME"), "photoarchive")
			if err := os.MkdirAll(dir, os.ModePerm); err != nil {
				return err
			}
			// Create photos directory
			photosDir := filepath.Join(dir, "photos")
			if err := os.MkdirAll(photosDir, os.ModePerm); err != nil {
				return err
			}
			return nil
		},
	})

	// Add command
	cmd.Commands = append(cmd.Commands, &cobra.Command{
		Name:   "add",
		Short: "Add a new photo entry",
		Args:  3,
		ArgsUsage: "add <date> <category> <description>",
		Help:   "Add a new photo with specified metadata",
		Runs: func(cmd *cobra.Command, args []string) {
			date, category, description := args[0], args[1], args[2]
			archive := &Archive{}
			archive.AddPhoto(date, category, description)
			fmt.Printf("Photo added: %s\n", archive.photos[len(archive.photos)-1].ID)
		},
	})

	// Report command
	cmd.Commands = append(cmd.Commands, &cobra.Command{
		Name:   "report",
		Short: "Generate a summary report of all photos by category",
		Args:  0,
		Help:   "Generate a summary report of all photos by category",
		Runs: func(cmd *cobra.Command, args []string) {
			archive := &Archive{}
			report := archive.Report()
			fmt.Println("Photo Report:")
			for category, descriptions := range report {
				fmt.Printf("Category: %s\n", category)
				for _, desc := range descriptions {
					fmt.Printf("  - %s\n", desc)
				}
			}
		},
	})

	// Execute the root command
	cmd.RootCmd.Execute()
}

