use futures::stream::FuturesUnordered;
use futures::Stream;
use std::fs::File;
use std::io::{BufRead, BufReader};
use std::path::Path;
use std::sync::{Arc, Mutex};
use std::time::Duration;
use tokio::fs;
use tokio::io::{AsyncRead, AsyncReadExt};
use tokio::task::spawn;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Read JSON input
    let json_content = std::fs::read_to_string("input.json")?;
    let file_paths: Vec<String> = serde_json::from_str(&json_content)?;

    // Create a new output file
    let output_path = "output.txt";
    let mut output_file = File::create(output_path)?;

    // Asynchronous read operations
    let mut streams = FuturesUnordered::new();
    let mut files = Vec::new();

    for path in &file_paths {
        let path = Path::new(path.as_str());
        let file = File::open(path)?;
        files.push(file);
        streams.push(tokio::spawn(async move {
            let mut reader = BufReader::new(file);
            let mut content = String::new();
            let _ = reader.read_to_string(&mut content);
            Ok(content)
        }));
    }

    // Concatenate all file contents
    let concatenated_content = futures::stream::try_fold(
        Vec::new(),
        |mut acc, res| {
            res.map(|content| {
                acc.extend(content.as_bytes());
                acc
            })
        },
    )
    .await?
    .into_iter()
    .collect::<Vec<u8>>();

    // Write concatenated content to output file
    output_file.write_all(&concatenated_content)?;
    output_file.flush()?;

    // Handle errors
    if let Err(e) = fs::remove_file(output_path) {
        eprintln!("Error removing output file: {}", e);
    }

    Ok(())
}
