use tide::prelude::*;
use tide::http::HeaderValue;
use serde::{Deserialize, Serialize};
use std::collections::BTreeSet;

#[derive(Debug, Serialize, Deserialize)]
struct ProductCode {
    code: String,
}

#[derive(Debug, Serialize, Deserialize)]
struct Response {
    valid_codes: BTreeSet<String>,
    invalid_codes: BTreeSet<String>,
}

#[async_trait::async_trait]
trait CodeValidator {
    async fn validate(&self, code: &str) -> Result<bool, String>;
}

struct ValidCodeValidator;

impl ValidCodeValidator for ValidCodeValidator {
    async fn validate(&self, code: &str) -> Result<bool, String> {
        if code.is_empty() {
            return Err("Code cannot be empty".to_string());
        }
        Ok(code.len() <= 10)
    }
}

#[async_trait::async_trait]
trait RequestHandler {
    async fn handle(&self, req: Request<Body>) -> Result<Response, String>;
}

struct RequestHandlerImpl;

impl RequestHandler for RequestHandlerImpl {
    async fn handle(&self, req: Request<Body>) -> Result<Response, String> {
        let mut res = Response {
            valid_codes: BTreeSet::new(),
            invalid_codes: BTreeSet::new(),
        };

        let body: String = match req.body().await {
            Ok(b) => b,
            Err(e) => return Err(format!("Failed to read request body: {}", e)),
        };

        let json: serde_json::Value = match serde_json::from_str(&body) {
            Ok(j) => j,
            Err(e) => return Err(format!("Malformed JSON: {}", e)),
        };

        let codes: Vec<String> = json
            .get("codes")
            .map(|v| v.as_array().map_or(Vec::new(), |a| a.iter().map(|s| s.to_string()).collect()))
            .unwrap_or_default();

        for code in codes {
            let code = code.trim().to_lowercase();
            let valid = match ValidCodeValidator::validate(&self).await {
                Ok(v) => v,
                Err(e) => return Err(e),
            };
            if valid {
                res.valid_codes.insert(code);
            } else {
                res.invalid_codes.insert(code);
            }
        }

        Ok(res)
    }
}

#[async_std::main]
async fn main() -> Result<(), String> {
    let mut app = tide::new();

    app.at("/").post(|req| async move {
        let handler = RequestHandlerImpl;
        handler.handle(req).await
    });

    app.listen("0.0.0.0:3030").await?;
    Ok(())
}
