use hyper::{Body, Request, Response, Server, StatusCode};
use hyper::header::{Content-Type, HeaderValue};
use hyper::client::Client;
use std::fs::File;
use std::io::{BufReader, BufWriter};
use std::path::Path;
use serde::{Deserialize, Serialize};
use serde_json::{json, to_string, Error, ToString};

#[derive(Serialize, Deserialize, PartialEq)]
struct Employee {
    id: u32,
    name: String,
    department: String,
    role: String,
}

#[derive(Deserialize)]
struct RequestData {
    employee_id: u32,
}

fn main() {
    // Define the employee data
    let employee_data = vec![
        Employee {
            id: 1,
            name: "Alice Smith".to_string(),
            department: "HR".to_string(),
            role: "Manager".to_string(),
        },
        Employee {
            id: 2,
            name: "Bob Johnson".to_string(),
            department: "Engineering".to_string(),
            role: "Developer".to_string(),
        },
    ];

    // Create a server
    let listener = hyper::net::TcpListener::bind("127.0.0.1:3000").unwrap();
    let server = Server::bind(listener).unwrap();
    let mut handle = server.handle();

    // Handle GET requests
    handle.handle(|req: Request<Body>| {
        // Check if the request is GET
        if req.method() == hyper::Method::GET {
            // Parse the request path
            let path = req.uri().path();
            if path.starts_with("/employees/") {
                let employee_id: u32 = path
                    .strip_prefix("/employees/")
                    .ok_or("Invalid path")?
                    .parse::<u32>()
                    .map_err(|_| "Invalid employee ID")?;

                // Find the employee
                let employee = employee_data.iter().find(|e| e.id == employee_id).ok_or("Employee not found")?;

                // Create response
                let response = Response::new(Body::from(
                    to_string(&json!({
                        "id": employee.id,
                        "name": employee.name,
                        "department": employee.department,
                        "role": employee.role,
                    }))
                    .unwrap_or_default(),
                ));

                // Set content type
                response.headers_mut().insert(
                    Content-Type,
                    HeaderValue::from_static("application/json"),
                );

                Ok(response)
            } else {
                // Invalid path
                let response = Response::new(Body::from("Invalid path"));
                Ok(response)
            }
        } else {
            // Invalid method
            let response = Response::new(Body::from("Invalid method"));
            Ok(response)
        }
    });

    // Run the server
    handle.run().unwrap();
}
