use tokio::net::TcpListener;
use tokio::spawn;
use serde_json::Value;
use std::collections::HashMap;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Create a TCP listener
    let listener = TcpListener::bind("127.0.0.1:8080").await?;

    // Map to store incoming requests
    let mut requests = HashMap::new();

    // Handle each incoming connection
    while let Ok((stream, addr)) = listener.accept().await {
        spawn(async move {
            // Read JSON from the stream
            let mut buffer = String::new();
            stream.read_to_end(&mut buffer).await?;

            // Parse JSON
            let json: Value = serde_json::from_str(&buffer).map_err(|e| {
                eprintln!("Error parsing JSON: {}", e);
                Box::new(e)
            })?;

            // Extract list of integers
            let integers: Vec<i32> = json["integers"]
                .as_array()
                .unwrap_or(&[])
                .iter()
                .map(|v| v.as_i32().unwrap_or(-1))
                .collect();

            // Asynchronously sort the integers
            let sorted = async {
                let sorted = integers
                    .iter()
                    .cloned()
                    .sorted_by(|a, b| a.cmp(b))
                    .collect::<Vec<_>>();
                sorted
            };

            // Wait for the sorted list to be ready
            let sorted = sorted.await?;

            // Send the sorted list back
            let mut response = String::new();
            response.push_str("{\"sorted\": [");
            for (i, &val) in sorted.iter().enumerate() {
                if i > 0 {
                    response.push(',');
                }
                response.push_str(&format!("{}]", val));
            }
            response.push_str("]}");

            // Write the response
            stream.write_all(response.as_bytes()).await?;
            stream.flush().await?;
        });
    }

    Ok(())
}
