            let mut buffer = [0; 1024];

            // Read message
            let n = reader.read(&mut buffer).await?;
            if n == 0 {
                return;
            }

            let message = std::str::from_utf8(&buffer[..n]).unwrap_or_default();

            // Handle message
            if let Some(msg) = message {
                if msg == "END" {
                    // Close the connection
                    writer.write_all(b"END").await?;
                    writer.flush().await?;
                    return;
                } else {
                    // Echo the message
                    writer.write_all(msg.as_bytes()).await?;
                    writer.flush().await?;
                }
            }
        }
    });

    server_handle.await?;
    Ok(())
}
