import { Either, left, right } from 'fp-ts/lib/Either';
import { Task, task } from 'fp-ts/lib/Task';
import { pipe } from 'fp-ts/lib/function';
import * as fs from 'fs';
import * as path from 'path';

// Define user configuration interface
interface UserSettings {
  theme: 'light' | 'dark';
  notifications: boolean;
  language: 'en' | 'es';
}

// Read user settings from JSON file
const readSettings = (): Task<UserSettings | null> => {
  const filePath = path.join(__dirname, 'user-settings.json');
  return task(() => {
    try {
      const data = fs.readFileSync(filePath, 'utf8');
      return JSON.parse(data) as UserSettings;
    } catch (err) {
      return left(new Error('Failed to read user settings'));
    }
  });
};

// Validate user settings using Either
const validateSettings = (settings: UserSettings): Either<Error, UserSettings> => {
  if (!settings.theme || !settings.notifications || !settings.language) {
    return left(new Error('Missing required fields'));
  }
  return right(settings);
};

// Update user settings
const updateSettings = (newSettings: UserSettings): Task<UserSettings> => {
  return task(() => {
    const validated = pipe(
      newSettings,
      validateSettings
    );
    if (validated.isLeft) {
      throw validated.right;
    }
    return newSettings;
  });
};

// Write user settings back to JSON file
const writeSettings = (settings: UserSettings): Task<void> => {
  const filePath = path.join(__dirname, 'user-settings.json');
  return task(() => {
    try {
      const data = JSON.stringify(settings, null, 2);
      fs.writeFileSync(filePath, data, 'utf8');
    } catch (err) {
      throw new Error('Failed to write user settings');
    }
  });
};

// Main service function
const userService = (): Task<void> => {
  return task(() => {
    try {
      const settings = readSettings().right;
      if (settings.isLeft) {
        throw settings.left;
      }
      const validated = validateSettings(settings.right);
      if (validated.isLeft) {
        throw validated.left;
      }
      const updated = updateSettings(validated.right);
      if (updated.isLeft) {
        throw updated.left;
      }
      writeSettings(updated.right).right;
    } catch (err) {
      throw err;
    }
  });
};

export default userService;

