// Define the schema
pub mod schema {
    use diesel::prelude::*;
    use diesel::sql_types::Text;

    #[derive(Queryable, AsExpression, Identifiable)]
    pub struct Book {
        pub id: i32,
        pub title: Text,
        pub author: Text,
        pub year_published: Text,
        pub quantity_in_stock: i32,
    }
}

// Define the database connection
fn connect_to_db() -> Result<Connection, Error> {
    dotenv::dotenv().ok();
    let db_url = env::var("DATABASE_URL").expect("DATABASE_URL not set");
    diesel::PgConnection::establish_connection(db_url)
}

// Define the book table
pub mod book {
    use super::*;

    pub fn create_table() {
        use diesel::prelude::*;
        use diesel::insert_into;
        use schema::book::TableName;

        insert_into(TableNames::Table)
            .values(&Book {
                id: 1,
                title: "Book 1",
                author: "Author 1",
                year_published: "2020",
                quantity_in_stock: 100,
            })
            .execute(&connect_to_db().unwrap())
            .unwrap();
    }
}

// Define the book service
pub mod book_service {
    use super::*;
    use diesel::prelude::*;
    use diesel::dsl::sql_query;
    use std::collections::HashMap;

    pub fn add_book(title: &str, author: &str, year_published: &str, quantity: i32) -> Result<(), Error> {
        use diesel::prelude::*;
        use diesel::insert_into;
        use schema::book::TableNames;

        let book = Book {
            title: title.to_string(),
            author: author.to_string(),
            year_published: year_published.to_string(),
            quantity_in_stock: quantity,
        };

        insert_into(TableNames::Table)
            .values(&book)
            .execute(&connect_to_db().unwrap())
            .map(|_| Ok(()))
            .map_err(|e| e)
    }

    pub fn update_book(id: i32, title: &str, author: &str, year_published: &str, quantity: i32) -> Result<(), Error> {
        use diesel::prelude::*;
        use diesel::update;
        use schema::book::TableNames;

        update(TableNames::Table)
            .set((
                book::TableNames::ColumnTitle.eq(title.to_string()),
                book::TableNames::ColumnAuthor.eq(author.to_string()),
                book::TableNames::ColumnYearPublished.eq(year_published.to_string()),
                book::TableNames::ColumnQuantityInStock.eq(quantity),
            ))
            .where(book::TableNames::ColumnId.eq(id))
            .execute(&connect_to_db().unwrap())
            .map(|_| Ok(()))
            .map_err(|e| e)
    }

    pub fn delete_book(id: i32) -> Result<(), Error> {
        use diesel::prelude::*;
        use diesel::delete;
        use schema::book::TableNames;

        delete(TableNames::Table)
            .where(book::TableNames::ColumnId.eq(id))
            .execute(&connect_to_db().unwrap())
            .map(|_| Ok(()))
            .map_err(|e| e)
    }

    pub fn get_books() -> Result<Vec<Book>, Error> {
        use diesel::prelude::*;
        use schema::book::TableNames;

        let books = TableNames::table()
            .load(&connect_to_db().unwrap())
            .map(|row| Book {
                id: row.id,
                title: row.title,
                author: row.author,
                year_published: row.year_published,
                quantity_in_stock: row.quantity_in_stock,
            })
            .map_err(|e| e)
    }

    pub fn get_books_by_title(title: &str) -> Result<Vec<Book>, Error> {
        use diesel::prelude::*;
        use schema::book::TableNames;

        let books = TableNames::table()
            .filter(book::TableNames::ColumnTitle.eq(title.to_string()))
            .load(&connect_to_db().unwrap())
            .map(|row| Book {
                id: row.id,
                title: row.title,
                author: row.author,
                year_published: row.year_published,
                quantity_in_stock: row.quantity_in_stock,
            })
            .map_err(|e| e)
    }

    pub fn get_books_by_author(author: &str) -> Result<Vec<Book>, Error> {
        use diesel::prelude::*;
        use schema::book::TableNames;

        let books = TableNames::table()
            .filter(book::TableNames::ColumnAuthor.eq(author.to_string()))
            .load(&connect_to_db().unwrap())
            .map(|row| Book {
                id: row.id,
                title: row.title,
                author: row.author,
                year_published: row.year_published,
                quantity_in_stock: row.quantity_in_stock,
            })
            .map_err(|e| e)
    }
}

// Main application
fn main() {
    // Connect to the database
    let conn = connect_to_db().unwrap();

    // Create the table if it doesn't exist
    book::create_table();

    // Example usage
    book_service::add_book("Book 2", "Author 2", "2021", 50).unwrap();
    book_service::update_book(1, "Book 1", "Author 1", "2020", 150).unwrap();
    book_service::delete_book(2).unwrap();

    // Query books
    let books = book_service::get_books().unwrap();
    println!("All books: {:?}", books);

    let title_books = book_service::get_books_by_title("Book 1").unwrap();
    println!("Books by title: {:?}", title_books);

    let author_books = book_service::get_books_by_author("Author 1").unwrap();
    println!("Books by author: {:?}", author_books);
}
