)

type Book struct {
	ISBN   string `json:"isbn"`
	Title  string `json:"title"`
	Author string `json:"author"`
	Stock  int    `json:"stock"`
}

type BookResponse struct {
	Book Book `json:"book"`
}

type BookListResponse struct {
	Books []Book `json:"books"`
}

func main() {
	chi := chi.New()

	// Middleware for logging
	chi.Use(middleware.Logger())

	// Routes
	chi.Route("/v1", func(r *chi.Mux) {
		r.Get("/books", getBooks)
		r.Post("/books", createBook)
		r.Delete("/books/{isbn}", deleteBook)
	})

	chi.Route("/v2", func(r *chi.Mux) {
		r.Get("/books", getBooks)
		r.Post("/books", createBook)
		r.Delete("/books/{isbn}", deleteBook)
	})

	chi.Route("/v3", func(r *chi.Mux) {
		r.Get("/books", getBooks)
		r.Post("/books", createBook)
		r.Delete("/books/{isbn}", deleteBook)
	})

	// Serve the API
	http.ListenAndServe(":8080", chi)
}

// Middleware for logging
func middlewareLogger(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		next.ServeHTTP(w, r)
		elapsed := time.Since(start)
		// Log request details
		_, _ = json.Marshal(map[string]interface{}{
			"method": r.Method,
			"url":     r.URL.Path,
			"status":  http.StatusOK,
			"elapsed": elapsed.String(),
		})
	})
}

// Get all books
func getBooks(w http.ResponseWriter, r *http.Request) {
	books := []Book{
		{ISBN: "1234567890", Title: "Book 1", Author: "Author 1", Stock: 10},
		{ISBN: "0987654321", Title: "Book 2", Author: "Author 2", Stock: 5},
	}

	response, _ := json.Marshal(books)
	w.Header().Set("Content-Type", "application/json")
	w.Write(response)
}

// Create a book
func createBook(w http.ResponseWriter, r *http.Request) {
	var book Book
	_ = json.NewDecoder(r.Body).Decode(&book)

	// Simple validation
	if book.ISBN == "" || book.Title == "" || book.Author == "" || book.Stock <= 0 {
		http.Error(w, "Missing or invalid data", http.StatusBadRequest)
		return
	}

	// Add to list (simulated)
	books := []Book{
		{ISBN: book.ISBN, Title: book.Title, Author: book.Author, Stock: book.Stock},
	}

	response, _ := json.Marshal(books)
	w.Header().Set("Content-Type", "application/json")
	w.Write(response)
}

// Delete a book by ISBN
func deleteBook(w http.ResponseWriter, r *http.Request) {
	isbn := r.URL.Path[7:] // /v1/books/{isbn}

	// Find and delete the book
	for i, book := range books {
		if book.ISBN == isbn {
			books = append(books[:i], books[i+1:]...)
			break
		}
	}

	response, _ := json.Marshal(books)
	w.Header().Set("Content-Type", "application/json")
	w.Write(response)
}

