        task::spawn(async move {
            let mut client = client.await;
            while let Ok(msg) = client.read().await {
                if let Ok(msg) = String::from_utf8(msg) {
                    let echoed = format!("Received: {}", msg);
                    client.write_all(echoed.as_bytes()).await?;
                }
            }
        });
    }

    Ok(())
