import { Controller, Post, Body, HttpException, HttpStatus } from '@nestjs/common';
import { UserService } from './user.service';
import { User } from './user.entity';

@Controller('users')
export class UserController {
  constructor(private readonly userService: UserService) {}

  @Post('register')
  async register(@Body() userData: User) {
    if (!userData.username || !userData.email || !userData.password) {
      throw new HttpException('Missing required fields', HttpStatus.BAD_REQUEST);
    }

    if (userData.username.length < 5 || userData.username.length > 15) {
      throw new HttpException('Username must be between 5 and 15 characters', HttpStatus.BAD_REQUEST);
    }

    if (!isValidEmail(userData.email)) {
      throw new HttpException('Invalid email format', HttpStatus.BAD_REQUEST);
    }

    if (!userData.password.match(/^(?=.*[A-Z])(?=.*[a-z])(?=.*\d).{8,20}$/)) {
      throw new HttpException('Password must contain at least one uppercase, one lowercase, one number, and be 8-20 characters long', HttpStatus.BAD_REQUEST);
    }

    const user = await this.userService.createUser(userData);
    return { message: 'User registered successfully', user };
  }
}

function isValidEmail(email: string): boolean {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}
