    id: ID!
    name: String!
    age: Int!
    address: String!
  }

  type Query {
    users: [User!]!
    user(id: ID!): User
  }

  type Mutation {
    createUser(name: String!, age: Int!, address: String!): User!
  }
`;

// Define the resolver
const resolvers = {
  Query: {
    users: () => dataSource.getRepository(User).find(),
    user: (_, { id }) => dataSource.getRepository(User).findOne({ where: { id } }),
  },
  Mutation: {
    createUser: (_, { name, age, address }) => {
      const user = new User();
      user.name = name;
      user.age = age;
      user.address = address;
      return dataSource.getRepository(User).save(user);
    },
  },
};

// Create the GraphQL server
const server = new GraphQLServer({
  typeDefs,
  resolvers,
});

// Start the server
server.start(() => console.log('Server is running on http://localhost:4000'));
