    // Simulate database update
    const updatedBook: Book = { ...book };
    return this.response.status(200).send({ data: updatedBook });
  }

  @tsoa.Delete('/books/:id')
  async deleteBook(@tsoa.Param('id') id: number): Promise<tsoa.Response> {
    // Simulate database deletion
    const index = books.findIndex(b => b.id === id);
    if (index === -1) {
      return this.response.status(404).send({ error: 'Book not found' });
