// Import Axios
import axios from 'axios';

// Function to handle file upload
async function uploadProductFile(file) {
  try {
    // Check if file is valid
    if (!file || file.type !== 'text/csv') {
      throw new Error('Invalid file type. Only CSV files are allowed.');
    }

    // Read the file content
    const reader = new FileReader();
    reader.onload = async (e) => {
      const csvContent = e.target.result;
      const data = csvContent.split('\n');

      // Parse CSV data
      const parsedData = data.map(row => {
        const [name, price, quantity] = row.split(',');
        return { name, price, quantity };
      });

      // Send POST request to API
      const response = await axios.post('https://api.examplecompany.com/products', parsedData, {
        headers: {
          'Content-Type': 'application/json'
        }
      });

      // Show success message
      alert('Product data uploaded successfully!');
    };

    reader.readAsText(file);
  } catch (error) {
    // Show error message
    alert('Error uploading product data: ' + error.message);
  }
}

