package main

import (
	"database/sql"
	"fmt"
	"log"
	"os"
	"time"

	_ "github.com/lib/pq"
	"github.com/jinzhu/gorm"
	"github.com/jinzhu/gorm/logger"
)

type Book struct {
	ID        int
	Title     string
	Author    string
	ISBN      string
	Quantity  int
	CreatedAt time.Time
	UpdatedAt time.Time
}

func main() {
	// Connect to PostgreSQL
	db, err := gorm.Open("postgres", os.Getenv("POSTGRES_URL"))
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	// Migrate the database
	db.AutoMigrate(&Book{})

	// Initialize logger
	logger := logger.New(
		logger.DefaultConfig,
		logger.NewLogOutput(os.Stderr),
		logger.NewLogOutput(os.Stdout),
	)
	db.Logger = logger

	// Define CRUD functions
	addBook := func(title, author, isbn, quantity int) error {
		newBook := Book{
			Title:     title,
			Author:    author,
			ISBN:      isbn,
			Quantity:  quantity,
			CreatedAt: time.Now(),
		}
		return db.Create(&newBook).Error
	}

	updateBook := func(id int, title, author, isbn, quantity int) error {
		var book Book
		db.Where("id = ?", id).Find(&book)
		if book.ID != id {
			return fmt.Errorf("book not found")
		}
		book.Title = title
		book.Author = author
		book.ISBN = isbn
		book.Quantity = quantity
		book.UpdatedAt = time.Now()
		return db.Save(&book).Error
	}

	deleteBook := func(id int) error {
		var book Book
		db.Where("id = ?", id).Delete(&book)
		return nil
	}

	fetchBooks := func() ([]Book, error) {
		var books []Book
		db.Find(&books)
		return books, nil
	}

	// Example usage
	fmt.Println("Starting bookstore application...")
	fmt.Println("Adding book: 'The Great Gatsby' by F. Scott Fitzgerald")
	if err := addBook("The Great Gatsby", "F. Scott Fitzgerald", "9780743273565", 10); err != nil {
		log.Fatal(err)
	}

	fmt.Println("Fetching all books...")
	books, err := fetchBooks()
	if err != nil {
		log.Fatal(err)
	}
	for _, book := range books {
		fmt.Printf("ID: %d, Title: %s, Author: %s, ISBN: %s, Quantity: %d\n", book.ID, book.Title, book.Author, book.ISBN, book.Quantity)
	}

	fmt.Println("Updating book: 'The Great Gatsby' to quantity 20")
	if err := updateBook(1, "The Great Gatsby", "F. Scott Fitzgerald", "9780743273565", 20); err != nil {
		log.Fatal(err)
	}

	fmt.Println("Deleting book with ID 1")
	if err := deleteBook(1); err != nil {
		log.Fatal(err)
	}
}

package main

import (
	"encoding/csv"
	"fmt"
	"log"
	"os"
	"strconv"
	"strings"
)

type TradingData struct {
	StockCode string
	Price     float64
	Volume    int
}

type TradingFirmActor struct {
	Actor
	StockCode string
}

func (a *TradingFirmActor) Receive(message Message) {
	switch message.Type {
	case "TRADE":
		// Parse trade data
		data := message.Data
		if len(data) < 3 {
			log.Println("Invalid trade data:", data)
			return
		}
		stockCode := data[0]
		price, err := strconv.ParseFloat(data[1], 64)
		if err != nil {
			log.Println("Invalid price:", data[1], "error:", err)
			return
		}
		volume, err := strconv.Atoi(data[2])
		if err != nil {
			log.Println("Invalid volume:", data[2], "error:", err)
			return
		}
		a.Store("trade", &TradingData{StockCode: stockCode, Price: price, Volume: volume})
	case "REQUEST_VOLUME":
		// Aggregate volume
		volume := 0
		for _, msg := range message.Data {
			if msg.Type == "TRADE" {
				volume += msg.Volume
			}
		}
		a.Store("volume", volume)
	case "REQUEST_HIGHEST_PRICE":
		// Aggregate highest price
		highPrice := 0.0
		for _, msg := range message.Data {
			if msg.Type == "TRADE" {
				if msg.Price > highPrice {
					highPrice = msg.Price
				}
			}
		}
		a.Store("highPrice", highPrice)
	}
}

func main() {
	// Load CSV data
	file, err := os.Open("trading_data.csv")
	if err != nil {
		log.Fatal(err)
	}
	defer file.Close()

	reader := csv.NewReader(file)
	for {
		record, err := reader.Read()
		if err == nil && len(record) > 0 {
			// Process each trade
			for i := 0; i < len(record); i++ {
				if i < 3 {
					stockCode := record[i]
					price, err := strconv.ParseFloat(record[i+1], 64)
					if err != nil {
						log.Println("Invalid price:", record[i+1], "error:", err)
						continue
					}
					volume, err := strconv.Atoi(record[i+2])
					if err != nil {
						log.Println("Invalid volume:", record[i+2], "error:", err)
						continue
					}
					// Create a new actor for this firm
					actor := &TradingFirmActor{}
					actor.Actor = NewActor()
					actor.StockCode = stockCode
					actor.Actor.Register("TRADE", func(msg Message) {
						// Process trade
						fmt.Printf("Received trade: %s, %f, %d\n", msg.Data[0], msg.Data[1], msg.Data[2])
					})
					actor.Actor.Register("REQUEST_VOLUME", func(msg Message) {
						// Aggregate volume
						fmt.Printf("Aggregate volume: %d\n", msg.Data[0])
					})
					actor.Actor.Register("REQUEST_HIGHEST_PRICE", func(msg Message) {
						// Aggregate highest price
						fmt.Printf("Aggregate highest price: %f\n", msg.Data[0])
					})
				}
			}
		} else {
			break
		}
	}
}

