package main

import (
	"fmt"
	"sync"
)

func concurrentSum(numbers []int, wg *sync.WaitGroup) {
	defer wg.Done()
	sum := 0
	for _, num := range numbers {
		sum += num
	}
	wg.Done()
}

func main() {
	numbers := []int{1, 2, 3, 4, 5}
	var wg sync.WaitGroup

	for i := range numbers {
		wg.Add(1)
		go concurrentSum(numbers, &wg)
	}

	wg.Wait()
	fmt.Println("Sum:", sum(numbers))
}

import requests
import json
import logging
import sys
from datetime import datetime

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def get_weather_data(api_url):
    try:
        response = requests.get(api_url)
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        logging.error(f"Error fetching weather data: {e}")
        return None

def parse_weather_data(data):
    try:
        temperature = data['main']['temp']
        humidity = data['main']['humidity']
        weather_description = data['weather'][0]['description']
        return {
            'temperature': temperature,
            'humidity': humidity,
            'weather_description': weather_description
        }
    except KeyError as e:
        logging.error(f"Missing key in weather data: {e}")
        return None

def format_output(data):
    try:
        return f"Temperature: {data['temperature']} K\nHumidity: {data['humidity']}%\nWeather: {data['weather_description']}"
    except KeyError as e:
        logging.error(f"Missing key in output data: {e}")
        return ""

def main():
    api_url = "https://api.openweathermap.org/data/2.5/weather?q=London&appid=YOUR_API_KEY&units=metric"
    data = get_weather_data(api_url)
    if data:
        parsed_data = parse_weather_data(data)
        if parsed_data:
            output = format_output(parsed_data)
            print(output)
    else:
        logging.warning("No weather data received.")

if __name__ == "__main__":
    main()
